from jinja2 import Environment

env = Environment(extensions=['jinja2.ext.i18n'])

def gettext(s):
    return 'GETTEXT:' + s

def ngettext(s, p, n):
    return ('NGETTEXT_S:' + s) if n == 1 else ('NGETTEXT_P:' + p)

def dgettext(domain, s):
    return f'DGETTEXT[{domain}]:' + s

def dngettext(domain, s, p, n):
    return (f'DNGETTEXT_S[{domain}]:' + s) if n == 1 else (f'DNGETTEXT_P[{domain}]:' + p)

env.install_gettext_callables(gettext, ngettext, newstyle=True)
env.globals['dgettext'] = dgettext
env.globals['dngettext'] = dngettext

tmpl = env.from_string('{% trans domain=\"myapp\" %}Hello World{% endtrans %}')
print(tmpl.render())

